questions.questionText:
다음 C 언어 프로그램이 실행되었을 때, 실행 결과는?

#include <stdio.h>

int main(int argc, char* argv[]) {
    int a = 5, b = 3, c = 12;
    int t1, t2, t3;
    t1 = a && b;
    t2 = a || b;
    t3 = !c;
    printf("%d", t1 + t2 + t3);
    return 0;
}

